const items = $input.all();
const alerts = [];
const pods = items[0]?.json?.items || [];

for (const pod of pods) {
  const name = pod.metadata?.name || 'unknown';
  const ns = pod.metadata?.namespace || 'default';
  const phase = pod.status?.phase;

  if (phase === 'Failed' || phase === 'Unknown') {
    alerts.push({ severity: 'CRITICAL', category: 'Pod', resource: `${ns}/${name}`,
      message: `Pod ${name} is in ${phase} state`, ts: new Date().toISOString() });
  }

  for (const cs of (pod.status?.containerStatuses || [])) {
    const waiting = cs.state?.waiting?.reason;
    if (waiting === 'CrashLoopBackOff') {
      alerts.push({ severity: 'CRITICAL', category: 'Pod', resource: `${ns}/${name}`,
        message: `Container ${cs.name} in CrashLoopBackOff (${cs.restartCount} restarts)`, ts: new Date().toISOString() });
    } else if (waiting === 'OOMKilled' || cs.lastState?.terminated?.reason === 'OOMKilled') {
      alerts.push({ severity: 'CRITICAL', category: 'Pod', resource: `${ns}/${name}`,
        message: `Container ${cs.name} was OOMKilled`, ts: new Date().toISOString() });
    } else if (waiting === 'ImagePullBackOff' || waiting === 'ErrImagePull') {
      alerts.push({ severity: 'WARNING', category: 'Pod', resource: `${ns}/${name}`,
        message: `Container ${cs.name}: ${waiting}`, ts: new Date().toISOString() });
    } else if ((cs.restartCount || 0) > 10) {
      alerts.push({ severity: 'WARNING', category: 'Pod', resource: `${ns}/${name}`,
        message: `Container ${cs.name} has ${cs.restartCount} restarts`, ts: new Date().toISOString() });
    }
  }

  if (phase === 'Pending') {
    const mins = Math.round((Date.now() - new Date(pod.metadata?.creationTimestamp).getTime()) / 60000);
    if (mins > 5) {
      alerts.push({ severity: 'WARNING', category: 'Pod', resource: `${ns}/${name}`,
        message: `Pod stuck in Pending for ${mins} minutes`, ts: new Date().toISOString() });
    }
  }
}

return alerts.length > 0 ? alerts.map(a => ({ json: a })) : [{ json: { severity: 'NONE', category: 'Pod', message: 'All pods healthy' } }];

const items = $input.all();
const alerts = [];
const nodes = items[0]?.json?.items || [];

for (const node of nodes) {
  const name = node.metadata?.name || 'unknown';
  const conditions = node.status?.conditions || [];

  const ready = conditions.find(c => c.type === 'Ready');
  if (ready?.status !== 'True') {
    alerts.push({ severity: 'CRITICAL', category: 'Node', resource: name,
      message: `Node ${name} is NotReady (${ready?.reason || 'unknown'})`, ts: new Date().toISOString() });
  }

  const memPressure = conditions.find(c => c.type === 'MemoryPressure');
  if (memPressure?.status === 'True') {
    alerts.push({ severity: 'CRITICAL', category: 'Node', resource: name,
      message: `Node ${name} under MemoryPressure`, ts: new Date().toISOString() });
  }

  const diskPressure = conditions.find(c => c.type === 'DiskPressure');
  if (diskPressure?.status === 'True') {
    alerts.push({ severity: 'WARNING', category: 'Node', resource: name,
      message: `Node ${name} under DiskPressure`, ts: new Date().toISOString() });
  }

  const pidPressure = conditions.find(c => c.type === 'PIDPressure');
  if (pidPressure?.status === 'True') {
    alerts.push({ severity: 'WARNING', category: 'Node', resource: name,
      message: `Node ${name} under PIDPressure`, ts: new Date().toISOString() });
  }

  if (node.spec?.unschedulable) {
    alerts.push({ severity: 'INFO', category: 'Node', resource: name,
      message: `Node ${name} is cordoned (unschedulable)`, ts: new Date().toISOString() });
  }
}

return alerts.length > 0 ? alerts.map(a => ({ json: a })) : [{ json: { severity: 'NONE', category: 'Node', message: 'All nodes healthy' } }];

const items = $input.all();
const alerts = [];
const deployments = items[0]?.json?.items || [];

for (const dep of deployments) {
  const name = dep.metadata?.name || 'unknown';
  const ns = dep.metadata?.namespace || 'default';
  const desired = dep.spec?.replicas || 0;
  const available = dep.status?.availableReplicas || 0;
  const ready = dep.status?.readyReplicas || 0;
  const unavailable = dep.status?.unavailableReplicas || 0;

  if (available === 0 && desired > 0) {
    alerts.push({ severity: 'CRITICAL', category: 'Deployment', resource: `${ns}/${name}`,
      message: `${name} has 0/${desired} available replicas`, ts: new Date().toISOString() });
  } else if (unavailable > 0) {
    alerts.push({ severity: 'WARNING', category: 'Deployment', resource: `${ns}/${name}`,
      message: `${name}: ${unavailable} unavailable (${ready}/${desired} ready)`, ts: new Date().toISOString() });
  }

  const progressing = (dep.status?.conditions || []).find(c => c.type === 'Progressing');
  if (progressing?.status === 'False' && progressing?.reason === 'ProgressDeadlineExceeded') {
    alerts.push({ severity: 'CRITICAL', category: 'Deployment', resource: `${ns}/${name}`,
      message: `${name} rollout stalled: ProgressDeadlineExceeded`, ts: new Date().toISOString() });
  }

  const replicaFailure = (dep.status?.conditions || []).find(c => c.type === 'ReplicaFailure');
  if (replicaFailure?.status === 'True') {
    alerts.push({ severity: 'WARNING', category: 'Deployment', resource: `${ns}/${name}`,
      message: `${name} replica failure: ${(replicaFailure.message || '').substring(0, 100)}`, ts: new Date().toISOString() });
  }
}

return alerts.length > 0 ? alerts.map(a => ({ json: a })) : [{ json: { severity: 'NONE', category: 'Deployment', message: 'All deployments healthy' } }];

const items = $input.all();
const alerts = [];
const events = items[0]?.json?.items || [];
const now = Date.now();
const recentWindow = 15 * 60 * 1000;

for (const evt of events) {
  const lastSeen = new Date(evt.lastTimestamp || evt.metadata?.creationTimestamp).getTime();
  if (now - lastSeen > recentWindow) continue;

  const name = evt.involvedObject?.name || 'unknown';
  const kind = evt.involvedObject?.kind || 'Unknown';
  const ns = evt.involvedObject?.namespace || '';
  const reason = evt.reason || '';
  const msg = evt.message || '';
  const count = evt.count || 1;

  let severity = 'INFO';
  const criticalReasons = ['OOMKilling', 'SystemOOM', 'NodeNotReady', 'Rebooted', 'EvictionThresholdMet'];
  const warningReasons = ['FailedScheduling', 'FailedMount', 'FailedAttachVolume', 'Unhealthy', 'BackOff', 'Evicted'];

  if (criticalReasons.includes(reason)) {
    severity = 'CRITICAL';
  } else if (warningReasons.includes(reason)) {
    severity = count > 5 ? 'CRITICAL' : 'WARNING';
  }

  if (severity !== 'INFO' || count > 3) {
    alerts.push({
      severity, category: 'Event', resource: `${kind}/${ns ? ns + '/' : ''}${name}`,
      message: `[${reason}] ${msg.substring(0, 200)}${count > 1 ? ' (x' + count + ')' : ''}`,
      ts: new Date().toISOString()
    });
  }
}

return alerts.length > 0 ? alerts.map(a => ({ json: a })) : [{ json: { severity: 'NONE', category: 'Event', message: 'No concerning events' } }];

const items = $input.all();

const alerts = items.filter(i => i.json.severity !== 'NONE');

if (alerts.length === 0) {
  return [{ json: { severity: 'NONE', alertCount: 0, message: 'Cluster healthy - no alerts' } }];
}

const seen = new Set();
const unique = [];
for (const item of alerts) {
  const key = `${item.json.category}:${item.json.resource}:${item.json.severity}`;
  if (!seen.has(key)) {
    seen.add(key);
    item.json.alertKey = key;
    unique.push(item);
  }
}

return unique;

